using System.Runtime.InteropServices;

class EnvVarCheck
{
    /// <summary>
    /// Checks whether an environment variable is defined in the process
    /// environment, even if its value is empty. Works around the .NET 9
    /// breaking change where empty env vars return null on Linux.
    /// </summary>
    private static bool IsEnvironmentVariableDefined(string variable)
    {
        if (RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
            return Environment.GetEnvironmentVariable(variable) != null;

        // On Unix, query /proc/self/environ or use the native getenv to
        // distinguish "not set" from "set to empty". IDictionary contains
        // every defined variable regardless of value.
        var allVars = Environment.GetEnvironmentVariables();
        return allVars.Contains(variable);
    }

    void CheckFlag()
    {

